const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
const now = new Date();
let yr = parseInt(pick(i['Year'], i.year), 10); if(isNaN(yr)) yr = now.getFullYear();
let focus = pick(i['Focus / region'], i['Focus'], i.focus);
const txt = pick(i.text).replace(/^\/calendar\b/i,'').trim();
if(!focus && txt && !/^\d{4}$/.test(txt)) focus = txt;
const audience = pick(i['Audience'], i.audience) || 'All staff';
// Layout: a year-on-a-page planner (default) or a month-per-page calendar.
let layout = pick(i['Layout'], i.layout).toLowerCase();
layout = /month|per.?page|wall/.test(layout) ? 'month' : 'year';

// --- Curated observances → correct dates per month (Configuration over hard
// coding): prefer config/awareness/observances.json, else a built-in default.
const OBS_DEFAULT = [
  { name:'Data Privacy Day', type:'fixed', month:1, day:28 },
  { name:'Safer Internet Day', type:'nth', month:2, weekday:2, n:2 },
  { name:'World Backup Day', type:'fixed', month:3, day:31 },
  { name:'Identity Management Day', type:'nth', month:4, weekday:2, n:2 },
  { name:'World Password Day', type:'nth', month:5, weekday:4, n:1 },
  { name:'Anti-Ransomware Day', type:'fixed', month:5, day:12 },
  { name:'Internet Safety Month', type:'month', month:6 },
  { name:'Cybersecurity Awareness Month', type:'month', month:10 },
  { name:'Computer Security Day', type:'fixed', month:11, day:30 }
];
let obsList = OBS_DEFAULT;
try { const p = require('fs').readFileSync('/config/awareness/observances.json','utf8'); const j = JSON.parse(p); if (j && Array.isArray(j.observances) && j.observances.length) obsList = j.observances; } catch (e) {}
const MAB = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const MFULL = ['January','February','March','April','May','June','July','August','September','October','November','December'];
function pad(n){ return (n<10?'0':'')+n; }
function nthWeekday(y, m, wd, n){ var first=new Date(y, m, 1).getDay(); var offset=(wd-first+7)%7; var day=1+offset+(n-1)*7; var dim=new Date(y, m+1, 0).getDate(); return day<=dim?day:null; }
const obsByMonth = []; for (var z=0; z<12; z++) obsByMonth.push([]);
const obsEvents = [];
obsList.forEach(function(o){
  if (!o || !o.name) return; var mi = (parseInt(o.month,10)||1)-1; if (mi<0||mi>11) return;
  if (o.type==='fixed' && o.day){ obsByMonth[mi].push(o.name+' — '+o.day+' '+MAB[mi]); obsEvents.push({ ymd:String(yr)+pad(mi+1)+pad(o.day), name:o.name }); }
  else if (o.type==='nth' && o.weekday!=null && o.n){ var dd=nthWeekday(yr, mi, parseInt(o.weekday,10), parseInt(o.n,10)); if (dd){ obsByMonth[mi].push(o.name+' — '+dd+' '+MAB[mi]); obsEvents.push({ ymd:String(yr)+pad(mi+1)+pad(dd), name:o.name }); } }
  else if (o.type==='month'){ obsByMonth[mi].push(o.name+' — '+MFULL[mi]); }
});
const obsText = obsByMonth.map(function(a,k){ return a.length?(MAB[k]+': '+a.join('; ')):''; }).filter(Boolean).join('  |  ');

return [{ json: { year:yr, focus:focus, audience:audience, layout:layout, obsByMonth:obsByMonth, obsEvents:obsEvents, obsText:obsText, topic:('Awareness campaign '+yr), date:now.toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString(), outDir:'calendar', filePrefix:'calendar', fileSafe:('campaign-'+yr) } }];

