  "messages": [ {"role":"user","content": {{ JSON.stringify('Design a 12-month security-awareness campaign calendar for the year ' + ($json.year||'') + '. Audience: ' + ($json.audience||'All staff') + ($json.focus?('. Focus/region: '+$json.focus):'') + '.' + ($json.obsText?(' Anchor the relevant months around these recognised observances and use their EXACT dates (do not invent other dates): '+$json.obsText):'')) }} } ]
}

