const layout = (r.layout === 'month') ? 'month' : 'year';
// Consistent, configurable theme. PRIMARY = deep brand colour; ACCENT = highlight.
function hex(v, dflt){ v=String(v||'').trim(); return /^#[0-9a-fA-F]{6}$/.test(v) ? v : dflt; }
